+    /// CanonicalizerDegradation serde roundtrip.
+    #[test]
+    fn canonicalizer_degradation_serde(variant in 0_u8..3) {
+        let deg = match variant {
+            0 => CanonicalizerDegradation::Healthy,
+            1 => CanonicalizerDegradation::HighDedupRatio { ratio: 0.75 },
